// Guardiao — Monitor 3: saude da conta Meta

const d = $input.first().json;
const status = d.account_status;
const balance = parseInt(d.balance || 0) / 100;  // em reais
const disableReason = d.disable_reason || 0;
const cardDisplay = (d.funding_source_details && d.funding_source_details.display_string) || 'nao identificado';

const agora = Date.now();
const COOLDOWN_MS = 6 * 60 * 60 * 1000;  // 6h

const staticData = $getWorkflowStaticData('global');
if (!staticData.alertas) staticData.alertas = {};
const historico = staticData.alertas;

// Mapeamento de account_status
const statusMap = {
  1: 'ACTIVE',
  2: 'DISABLED',
  3: 'UNSETTLED',
  7: 'PENDING_RISK_REVIEW',
  8: 'PENDING_SETTLEMENT',
  9: 'IN_GRACE_PERIOD',
  100: 'PENDING_CLOSURE',
  101: 'CLOSED'
};

// Mapeamento de disable_reason
const reasonMap = {
  0: 'nenhum',
  1: 'ADS_INTEGRITY_POLICY',
  2: 'ADS_IP_REVIEW',
  3: 'RISK_PAYMENT',
  4: 'GRAY_ACCOUNT_SHUT_DOWN',
  5: 'ADS_AFC_REVIEW',
  6: 'BUSINESS_INTEGRITY_RAR',
  7: 'PERMANENT_CLOSE',
  8: 'UNUSED_RESELLER_ACCOUNT',
  9: 'UNUSED_ACCOUNT'
};

const alertas = [];

// 1. Status da conta
if (status !== 1) {
  const key = 'status_' + status;
  if (!historico[key] || (agora - historico[key]) > COOLDOWN_MS) {
    alertas.push({
      tipo: 'conta_desativada',
      gravidade: 'critico',
      status_codigo: status,
      status_texto: statusMap[status] || 'UNKNOWN',
      disable_reason_codigo: disableReason,
      disable_reason_texto: reasonMap[disableReason] || 'UNKNOWN',
      balance,
      cartao: cardDisplay
    });
    historico[key] = agora;
  }
}

// 2. Saldo devedor alto (> R$500 em aberto, sinal de cobranca falhando)
if (balance > 500) {
  const key = 'balance_alto';
  if (!historico[key] || (agora - historico[key]) > COOLDOWN_MS) {
    alertas.push({
      tipo: 'saldo_devedor_alto',
      gravidade: balance > 2000 ? 'critico' : 'atencao',
      balance,
      cartao: cardDisplay,
      explicacao: 'Saldo devedor em aberto. Facebook pode estar tentando cobrar no cartao e nao conseguindo. Se continuar subindo, anuncios podem ser pausados automaticamente.'
    });
    historico[key] = agora;
  }
}

// 3. Balance cresceu muito rapido desde ultima checagem
if (staticData.ultimo_balance !== undefined && balance > staticData.ultimo_balance + 500) {
  const key = 'balance_crescendo';
  if (!historico[key] || (agora - historico[key]) > COOLDOWN_MS) {
    alertas.push({
      tipo: 'balance_crescendo_sem_cobranca',
      gravidade: 'atencao',
      balance,
      balance_anterior: staticData.ultimo_balance,
      diferenca: balance - staticData.ultimo_balance,
      cartao: cardDisplay,
      explicacao: 'Saldo devedor cresceu sem ser cobrado. Provavel falha de cobranca no cartao.'
    });
    historico[key] = agora;
  }
}

staticData.ultimo_balance = balance;

// Limpar historico antigo
for (const k of Object.keys(historico)) {
  if (agora - historico[k] > 48 * 60 * 60 * 1000) delete historico[k];
}

if (alertas.length === 0) {
  return [{json: {nenhum_alerta: true, status_atual: statusMap[status], balance_atual: balance}}];
}

return alertas.map(a => ({json: a}));
